SELECT DISTINCT ?team ?teamLabel WHERE { 
  ?team wdt:P31/wdt:P279* wd:Q4779686 ; 
        p:P166 ?statement1 .
  ?statement1 ps:P166 wd:Q211872 ;
               pq:P585 ?time1 .
  ?team p:P166 ?statement2 .
  ?statement2 ps:P166 wd:Q211872 ;
               pq:P585 ?time2 .
  ?team p:P166 ?statement3 .
  ?statement3 ps:P166 wd:Q211872 ;
               pq:P585 ?time3 .
  FILTER (?statement1 != ?statement2 && ?statement2 != ?statement3 && ?statement1 != ?statement3) 
  BIND(YEAR(?time1) AS ?year1)
  BIND(YEAR(?time2) AS ?year2)
  BIND(YEAR(?time3) AS ?year3)
  FILTER (?year2 = ?year1 + 1)
  FILTER (?year3 = ?year2 + 1)
  OPTIONAL { ?team rdfs:label ?teamLabel . FILTER (lang(?teamLabel) = "en") }
}
ORDER BY ?team
LIMIT 10

